1	use crate::runtime::{Example, StepResult, World};
2	use shared::{
3	    accumulate_sum_source, ensure_fixture_dir, resolve_arg_paths, resolve_params,
4	    step_then_exit_code, step_then_no_duplicate_pair, step_then_stdout_reports_pair_for,
5	    write_fixture,
6	};
7	use std::cell::RefCell;
8	use std::path::Path;
9	use std::process::Command;
10	use std::sync::OnceLock;
11	
12	mod shared {
13	    include!("shared.rs");
14	}
15	
16	thread_local! {
17	    static HAS_GIT_WORK_TREE: RefCell<bool> = const { RefCell::new(false) };
18	    static GIT_ABSENT: RefCell<bool> = const { RefCell::new(false) };
19	    // True when using the real project dir (dogfood mode), not a temp fixture
20	    static DOGFOOD_MODE: RefCell<bool> = const { RefCell::new(false) };
21	}
22	
23	#[allow(dead_code)]
24	pub fn reset_test_state() {
25	    shared::FIXTURE_DIR.with(|d| *d.borrow_mut() = None);
26	    shared::FIXTURE_ROOT.with(|r| *r.borrow_mut() = None);
27	    HAS_GIT_WORK_TREE.with(|f| *f.borrow_mut() = false);
28	    GIT_ABSENT.with(|f| *f.borrow_mut() = false);
29	    DOGFOOD_MODE.with(|f| *f.borrow_mut() = false);
30	}
31	
32	pub fn dispatch(step_text: &str, world: &mut World, example: &Example) -> StepResult {
33	    let step = resolve_params(step_text, example);
34	    let s = step.as_str();
35	
36	    macro_rules! try_step {
37	        ($fn:ident) => {
38	            if let Some(r) = $fn(s, world) {
39	                return r;
40	            }
41	        };
42	    }
43	
44	    try_step!(step_given_rust_file_with_structure_and_ids);
45	    try_step!(step_given_git_work_tree);
46	    try_step!(step_given_gitignore_entry);
47	    try_step!(step_given_no_git_executable);
48	    try_step!(step_given_not_inside_git_work_tree);
49	    try_step!(step_given_project_source_dir);
50	    try_step!(step_when_run_drywall_with_args);
51	    try_step!(step_when_run_drywall_twice_with_args);
52	    try_step!(step_then_exit_code);
53	    try_step!(step_then_both_runs_share_exit_code);
54	    try_step!(step_then_both_runs_byte_identical_stdout);
55	    try_step!(step_then_stdout_reports_pair_for);
56	    try_step!(step_then_no_duplicate_pair);
57	    try_step!(step_then_stderr_empty);
58	
59	    StepResult::fail(format!("unsupported step: {}", s))
60	}
61	
62	fn step_given_rust_file_with_structure_and_ids(step: &str, _world: &mut World) -> Option<StepResult> {
63	    static RE: OnceLock<regex::Regex> = OnceLock::new();
64	    let re = RE.get_or_init(|| {
65	        regex::Regex::new(
66	            r#"^a Rust file "([^"]+)" containing a function with structure "([^"]+)" and identifiers "([^"]+)"$"#,
67	        ).unwrap()
68	    });
69	    let caps = re.captures(step)?;
70	    let file = caps.get(1).unwrap().as_str();
71	    let _structure = caps.get(2).unwrap().as_str();
72	    let ids = caps.get(3).unwrap().as_str();
73	
74	    let root = match ensure_fixture_dir() {
75	        Ok(r) => r,
76	        Err(e) => return Some(e),
77	    };
78	
79	    let content = accumulate_sum_source(ids);
80	    match write_fixture(&root, file, &content) {
81	        Ok(()) => Some(StepResult::ok()),
82	        Err(e) => Some(e),
83	    }
84	}
85	
86	fn step_given_git_work_tree(step: &str, _world: &mut World) -> Option<StepResult> {
87	    if step != "a git work tree with a git executable available" {
88	        return None;
89	    }
90	    // In dogfood mode the real project is already a git work tree
91	    if DOGFOOD_MODE.with(|f| *f.borrow()) {
92	        HAS_GIT_WORK_TREE.with(|f| *f.borrow_mut() = true);
93	        return Some(StepResult::ok());
94	    }
95	    let root = match ensure_fixture_dir() {
96	        Ok(r) => r,
97	        Err(e) => return Some(e),
98	    };
99	    let status = Command::new("git")
100	        .args(["-C", &root, "init"])
101	        .stdout(std::process::Stdio::null())
102	        .stderr(std::process::Stdio::null())
103	        .status();
104	    match status {
105	        Ok(s) if s.success() => {
106	            HAS_GIT_WORK_TREE.with(|f| *f.borrow_mut() = true);
107	            Some(StepResult::ok())
108	        }
109	        Ok(s) => Some(StepResult::fail(format!("git init failed: {:?}", s))),
110	        Err(e) => Some(StepResult::fail(format!("failed to run git init: {}", e))),
111	    }
112	}
113	
114	fn step_given_gitignore_entry(step: &str, _world: &mut World) -> Option<StepResult> {
115	    static RE: OnceLock<regex::Regex> = OnceLock::new();
116	    let re = RE.get_or_init(|| {
117	        regex::Regex::new(r#"^a gitignore entry "([^"]+)"$"#).unwrap()
118	    });
119	    let caps = re.captures(step)?;
120	    let pattern = caps.get(1).unwrap().as_str();
121	
122	    let root = match ensure_fixture_dir() {
123	        Ok(r) => r,
124	        Err(e) => return Some(e),
125	    };
126	
127	    let gitignore = Path::new(&root).join(".gitignore");
128	    let existing = std::fs::read_to_string(&gitignore).unwrap_or_default();
129	    let new_content = format!("{}{}\n", existing, pattern);
130	    match std::fs::write(&gitignore, new_content) {
131	        Ok(()) => Some(StepResult::ok()),
132	        Err(e) => Some(StepResult::fail(format!("write .gitignore: {}", e))),
133	    }
134	}
135	
136	fn step_given_no_git_executable(step: &str, _world: &mut World) -> Option<StepResult> {
137	    if step != "no git executable is available" {
138	        return None;
139	    }
140	    GIT_ABSENT.with(|f| *f.borrow_mut() = true);
141	    Some(StepResult::ok())
142	}
143	
144	fn step_given_not_inside_git_work_tree(step: &str, _world: &mut World) -> Option<StepResult> {
145	    if step != "a directory that is not inside a git work tree" {
146	        return None;
147	    }
148	    match ensure_fixture_dir() {
149	        Ok(_) => Some(StepResult::ok()),
150	        Err(e) => Some(e),
151	    }
152	}
153	
154	fn step_given_project_source_dir(step: &str, _world: &mut World) -> Option<StepResult> {
155	    static RE: OnceLock<regex::Regex> = OnceLock::new();
156	    let re = RE.get_or_init(|| {
157	        regex::Regex::new(r#"^the drywall project source directory at "([^"]+)"$"#).unwrap()
158	    });
159	    let _caps = re.captures(step)?;
160	    // Dogfood: use real project directory, not a temp fixture
161	    shared::FIXTURE_DIR.with(|d| *d.borrow_mut() = None);
162	    shared::FIXTURE_ROOT.with(|r| *r.borrow_mut() = None);
163	    HAS_GIT_WORK_TREE.with(|f| *f.borrow_mut() = false);
164	    GIT_ABSENT.with(|f| *f.borrow_mut() = false);
165	    DOGFOOD_MODE.with(|f| *f.borrow_mut() = true);
166	    Some(StepResult::ok())
167	}
168	
169	fn step_when_run_drywall_with_args(step: &str, world: &mut World) -> Option<StepResult> {
170	    static RE: OnceLock<regex::Regex> = OnceLock::new();
171	    let re = RE.get_or_init(|| {
172	        regex::Regex::new(r#"^I run drywall with the arguments "([^"]*)"$"#).unwrap()
173	    });
174	    let caps = re.captures(step)?;
175	    let raw_args = caps.get(1).map_or("", |m| m.as_str());
176	
177	    let binary = std::env::var("DRYWALL_BINARY")
178	        .unwrap_or_else(|_| "./target/release/drywall".to_string());
179	
180	    let resolved = resolve_arg_paths(raw_args);
181	
182	    world.binary_path = Some(binary.clone());
183	
184	    let git_absent = GIT_ABSENT.with(|f| *f.borrow());
185	
186	    let output = if git_absent {
187	        // Strip git from PATH so drywall cannot find the git executable
188	        let path_without_git = std::env::var("PATH").unwrap_or_default();
189	        let filtered: Vec<&str> = path_without_git
190	            .split(':')
191	            .filter(|dir| {
192	                let git_path = Path::new(dir).join("git");
193	                !git_path.exists()
194	            })
195	            .collect();
196	        let new_path = filtered.join(":");
197	        Command::new(&binary)
198	            .args(&resolved)
199	            .env("PATH", &new_path)
200	            .output()
201	    } else {
202	        Command::new(&binary).args(&resolved).output()
203	    };
204	
205	    let output = match output {
206	        Ok(o) => o,
207	        Err(e) => return Some(StepResult::fail(format!("failed to run binary: {}", e))),
208	    };
209	
210	    world.exit_code = Some(output.status.code().unwrap_or(-1));
211	    world.stdout = Some(String::from_utf8_lossy(&output.stdout).to_string());
212	    world.stderr = Some(String::from_utf8_lossy(&output.stderr).to_string());
213	    Some(StepResult::ok())
214	}
215	
216	fn step_then_stderr_empty(step: &str, world: &mut World) -> Option<StepResult> {
217	    if step != "stderr is empty" {
218	        return None;
219	    }
220	    let stderr = match &world.stderr {
221	        Some(s) => s.clone(),
