use crate::ast::{extract_functions, parse_source_tree};
use crate::core::FunctionInfo;
use globset::{Glob, GlobSet, GlobSetBuilder};
use std::path::{Component, Path};
use std::process::Command;
use walkdir::WalkDir;

const BUILTIN_EXCLUDED_DIRS: &[&str] = &[
    ".git",
    "target",
    "node_modules",
    "__pycache__",
    "vendor",
    "dist",
    ".next",
];

pub fn is_builtin_excluded(path: &Path) -> bool {
    path.components().any(|c| {
        if let Component::Normal(name) = c {
            BUILTIN_EXCLUDED_DIRS.contains(&name.to_str().unwrap_or(""))
        } else {
            false
        }
    })
}

fn git_check_ignore(path: &Path) -> Option<bool> {
    let abs = path.canonicalize().ok()?;
    let parent = abs.parent()?;
    let output = Command::new("git")
        .args([
            "-C",
            &parent.to_string_lossy(),
            "check-ignore",
            "--",
            &abs.to_string_lossy(),
        ])
        .output()
        .ok()?;
    Some(output.status.code() == Some(0))
}

pub fn is_git_ignored(path: &Path) -> bool {
    git_check_ignore(path).unwrap_or(false)
}

pub fn build_glob_set(patterns: &[String]) -> Result<GlobSet, globset::Error> {
    let mut builder = GlobSetBuilder::new();
    for pat in patterns {
        builder.add(Glob::new(pat)?);
    }
    builder.build()
}

pub fn is_rust_file(path: &Path) -> bool {
    path.extension().and_then(|e| e.to_str()) == Some("rs")
}

pub fn should_skip(path: &Path, exclude_set: &GlobSet) -> bool {
    if exclude_set.is_empty() {
        return false;
    }
    exclude_set.is_match(path)
}

pub fn collect_all_functions(
    paths: &[String],
    exclude_set: &GlobSet,
) -> (Vec<FunctionInfo>, Vec<String>) {
    let mut functions: Vec<FunctionInfo> = Vec::new();
    let mut errors: Vec<String> = Vec::new();
    for path_str in paths {
        let path = Path::new(path_str);
        if !path.exists() {
            errors.push(format!("path does not exist: {}", path_str));
        } else {
            collect_functions_from_path(path, exclude_set, &mut functions, &mut errors);
        }
    }
    (functions, errors)
}

pub fn collect_functions_from_path(
    path: &Path,
    exclude_set: &GlobSet,
    functions: &mut Vec<FunctionInfo>,
    errors: &mut Vec<String>,
) {
    if path.is_file() {
        collect_from_single_file(path, exclude_set, functions, errors);
    } else {
        collect_from_directory(path, exclude_set, functions, errors);
    }
}

pub fn should_scan_file(
    path: &Path,
    exclude_set: &GlobSet,
    git_ignored: &dyn Fn(&Path) -> bool,

content.content:
100	    git_ignored: &dyn Fn(&Path) -> bool,
101	) -> bool {
102	    !is_builtin_excluded(path)
103	        && is_rust_file(path)
104	        && !should_skip(path, exclude_set)
105	        && !git_ignored(path)
106	}
107	
108	pub fn collect_from_single_file(
109	    path: &Path,
110	    exclude_set: &GlobSet,
111	    functions: &mut Vec<FunctionInfo>,
112	    errors: &mut Vec<String>,
113	) {
114	    if should_scan_file(path, exclude_set, &is_git_ignored) {
115	        process_file(path, functions, errors);
116	    }
117	}
118	
119	fn process_entry(
120	    entry: Result<walkdir::DirEntry, walkdir::Error>,
121	    exclude_set: &GlobSet,
122	    functions: &mut Vec<FunctionInfo>,
123	    errors: &mut Vec<String>,
124	) {
125	    match entry {
126	        Ok(e)
127	            if e.file_type().is_file()
128	                && should_scan_file(e.path(), exclude_set, &is_git_ignored) =>
129	        {
130	            process_file(e.path(), functions, errors);
131	        }
132	        Ok(_) => {}
133	        Err(err) => errors.push(format!("walk error: {}", err)),
134	    }
135	}
136	
137	pub fn collect_from_directory(
138	    path: &Path,
139	    exclude_set: &GlobSet,
140	    functions: &mut Vec<FunctionInfo>,
141	    errors: &mut Vec<String>,
142	) {
143	    let walker = WalkDir::new(path)
144	        .sort_by_file_name()
145	        .into_iter()
146	        .filter_entry(|e| !e.file_type().is_dir() || !is_builtin_excluded(e.path()));
147	    for entry in walker {
148	        process_entry(entry, exclude_set, functions, errors);
149	    }
150	}
151	
152	pub fn process_file(path: &Path, functions: &mut Vec<FunctionInfo>, errors: &mut Vec<String>) {
153	    let source = match std::fs::read_to_string(path) {
154	        Ok(s) => s,
155	        Err(e) => {
156	            errors.push(format!("cannot read {}: {}", path.display(), e));
157	            return;
158	        }
159	    };
160	
161	    match parse_source_tree(&source) {
162	        Ok(tree) => {
163	            let file_str = path.to_string_lossy().to_string();
164	            extract_functions(tree.root_node(), &source, &file_str, functions);
165	        }
166	        Err(msg) => {
167	            errors.push(format!("{} in {}", msg, path.display()));
168	        }
169	    }
170	}
